exercises.solution_code:
#include <iostream>

int main() {
    int a {}, b {};
    std::cin >> a >> b;

    if (a > b)
        std::cout << "a is greater\n";
    else
        std::cout << "b is greater or equal\n";

    std::cout << "Done.\n";
    return 0;
}

