        goto save;
    if (choice == 2)
        goto load;
    if (choice == 3)
        goto quit;
    goto unknown;

save:
    std::cout << "Action: Save\n";
    goto end;
load:
    std::cout << "Action: Load\n";
    goto end;
quit:
    std::cout << "Action: Quit\n";
    goto end;
unknown:
    std::cout << "Action: Unknown\n";

end:
    std::cout << "Menu complete.\n";
    return 0;
}

exercises.solution_code:
#include <iostream>

int main() {
    int choice{};
    std::cin >> choice;

    if (choice == 1) {
        std::cout << "Action: Save\n";
    } else if (choice == 2) {
        std::cout << "Action: Load\n";
    } else if (choice == 3) {
        std::cout << "Action: Quit\n";
    } else {
        std::cout << "Action: Unknown\n";
    }

    std::cout << "Menu complete.\n";
    return 0;
}
